import React, { useRef, useEffect, useState } from 'react';
import { MapContainer, TileLayer, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { generateMapOverlayDoc } from './generateMapOverlayDoc';
import { SelectionOverlay } from './SelectionOverlay';
import html2canvas from 'html2canvas';

// Icons for the map
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
  iconUrl: require('leaflet/dist/images/marker-icon.png'),
  shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

interface MapViewerProps {
  importedMapBlob: Blob | null;
  mapBounds: [[number, number], [number, number]] | null;
  isSelectionMode: boolean;
  onImageGenerated: (doc: any) => void;
  onSelectionModeChange: (isSelectionMode: boolean) => void;
}

export const MapViewer: React.FC<MapViewerProps> = ({
  importedMapBlob,
  mapBounds,
  isSelectionMode,
  onImageGenerated,
  onSelectionModeChange,
}) => {
  const mapRef = useRef<any>(null);
  const [mapImage, setMapImage] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleCapture = async () => {
    if (containerRef.current) {
      try {
        const canvas = await html2canvas(containerRef.current, {
          useCORS: true, // IMPORTANT to allow cross-origin images
        });
        const dataURL = canvas.toDataURL('image/png');
        setMapImage(dataURL);
        const doc = await generateMapOverlayDoc(dataURL);
        onImageGenerated(doc);
      } catch (error) {
        console.error('Error during screen capture:', error);
      }
    }
  };

  useEffect(() => {
    if (isSelectionMode) {
      handleCapture();
    }
  }, [isSelectionMode]);

  return (
    <div
      ref={containerRef}
      style={{
        position: 'relative',
        width: '100%',
        height: '100%',
        zIndex: 10,
        backgroundColor: 'lightgray',
      }}
    >
      <MapContainer
        ref={mapRef}
        center={[0, 0]}
        zoom={2}
        style={{ width: '100%', height: '100%' }}
        scrollWheelZoom={true}
        attributionControl={false}
        dragging={true}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        />
        {mapBounds && (
          <BoundsEffect bounds={mapBounds} />
        )}
      </MapContainer>
      <SelectionOverlay
        containerRef={containerRef}
        active={isSelectionMode}
        onComplete={handleCapture}
      />
    </div>
  );
};

const BoundsEffect: React.FC<{ bounds: [[number, number], [number, number]] }> = ({ bounds }) => {
  const map = useMap();
  useEffect(() => {
    if (bounds) {
      map.fitBounds(bounds);
    }
  }, [map, bounds]);
  return null;
};
```


**Isolating Core Capture**

The logic in `App.tsx` requires immediate attention. I believe the "Extract Map CapScreen" action needs to exclusively trigger `SelectionOverlay`. This means I should bypass the conditional checks and focus on ensuring that the `SelectionOverlay` always activates the screen capture mode. This should simplify the flow, and ensure that the user can use the capture functionality whenever they choose, without any interference.
